WITH c AS (INSERT INTO chapters (book_id, slug, title, position) VALUES ('f1bae824-5378-4152-b8d9-f25d730af107', 'paatosluku-mita-nyt', 'Päätösluku — Mitä nyt', 6) RETURNING id) INSERT INTO sections (chapter_id, title, content, position) VALUES
((SELECT id FROM c), 'Mitä nyt', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Kirje tältä hetkeltä. Tämä kirja on kirjoitettu hetkellä joka ei toistu."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ei siksi, että kaikki hetket ovat ainutlaatuisia — ne ovat — vaan siksi, että tämä hetki on erityinen sillä tavalla joka on historiassa harvinainen: se on siirtymäkohta. Ei dramaattinen murros, ei yksittäinen tapahtuma, vaan hitaasti kiihtyvä muutos jonka suunta on jo selvä mutta jonka päätepisteestä ei tiedetä mitään."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Juuri tässä kohdassa olemme. Juuri tätä lukiessasi."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Johdannossa esitettiin lupaus: ei vastauksia, mutta parempi perspektiivi. Toivottavasti se lupaus on pidetty."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Neljä miljardia vuotta, viisi lukua, yksi ketju. Syanobakteerit joilla ei ollut aikomuksia mutta jotka muuttivat kaiken. Fossiiliset polttoaineet jotka olivat sekä katalysaattori että uhka. Tietoisuus jonka alkuperää ei tunneta ja jonka tulevaisuudesta ei tiedetä. Jumalten äänet jotka vaikenivat kun kirjoitustaito synnytti sisäisen monologin. Järjestelmät jotka alkavat optimoida itseään alkuperäisen tehtävänsä sijaan, ja edessä on kaksi polkua joista ei tiedetä kummalla kuljetaan."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tämä on rehellinen kuva tilanteesta. Se ei ole lohdullinen eikä lohduttava — se on todellinen."}]}]}'::jsonb, 0),
((SELECT id FROM c), 'Mitä perspektiivi tekee', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "On yksi asia jota pitkä perspektiivi tekee väistämättä: se muuttaa sen mikä tuntuu suurelta ja sen mikä tuntuu pieneltä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Päivittäinen uutisvirta on täynnä asioita jotka tuntuvat ratkaisevilta. Poliittiset kiistat, talousluvut, skandaalit, kriisit. Kaikki nämä ovat todellisia ja jotkut niistä tärkeitä. Mutta neljän miljardin vuoden perspektiivistä katsottuna ne ovat aallokkoa pinnalla — todellista liikettä, mutta ei se virta joka ratkaisee lopulta mihin mennään."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Virta on syvemmällä. Se on tässä kirjassa kuvattu ketju: kompleksisuuden kasvu, kokemuksen syntyminen, tietoisuuden laajeneminen, siirtymä seuraavalle tasolle. Tämä virta ei pysähdy poliittisiin kriiseihin eikä taloustaantumiin. Se on hitaampaa ja väistämättömämpää kuin mikään yksittäinen tapahtuma."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Mutta — ja tämä on tärkeä mutta — virta ei myöskään ole deterministinen. Syanobakteerit olisivat voineet tuottaa erilaisen katastrofin. Kivihiilikaudun metsät olisivat voineet hajota eri tavalla. Ihminen olisi voinut käyttää fossiilisia polttoaineita eri tahdissa. Jokainen siirtymä on ollut todellinen — mutta se olisi voinut mennä toisin."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Sama pätee nyt. Siirtymä on tulossa. Mutta sen laatu, nopeus ja sisältö — ne ovat vielä auki."}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Perspektiivi ei poista vastuuta. Se paljastaa missä vastuu todella sijaitsee."}]}]}]}'::jsonb, 1),
((SELECT id FROM c), 'Kolme asiaa joita tämä hetki vaatii', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Jos tässä kirjassa on jokin käytännöllinen sanoma, se on tässä. Ei toimintaohjelma, ei lista tehtäviä — mutta kolme asennetta joita tämä hetki tuntuu vaativan."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ensimmäinen on ihmetys ilman naiiviyttä. Tekoäly on hämmästyttävä. Ihmiskunnan kyky rakentaa järjestelmiä jotka ylittävät yksittäisen ihmisen kyvyt on historiallisesti poikkeuksellinen saavutus. Tämä ansaitsee hämmästelyn — ei kyynisyyttä eikä pelkoa oletusasentona, vaan aitoa ihmetystä siitä mitä on tapahtunut. Samalla ihmetyksen ei pidä sammuttaa kriittisyyttä. Syanobakteeritkin olivat hämmästyttäviä — ja ne tuottivat massasukupuuton."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Toinen on rehellisyys epävarmuuden kanssa. Yksinkertaiset vastaukset ovat houkuttelevia. Tekoäly pelastaa maailman. Tekoäly tuhoaa maailman. Kumpikaan ei ole totta sellaisenaan. Totuus on monimutkaisempi, epävarmempi, ja vaatii sietämään tilaa jossa ei tiedetä. Tämä on vaikeampaa kuin valita puoli — mutta se on ainoa rehellinen asento."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Kolmas on läsnäolo tässä hetkessä. Pitkä perspektiivi voi tehdä yksittäisen elämän tuntumaan merkityksettömältä — mitä yksi ihminen merkitsee neljän miljardin vuoden tarinassa? Mutta fraktaalin logiikka kertoo muuta. Jokainen taso on välttämätön. Jokainen solu on välttämätön organismille. Jokainen ihminen on välttämätön sille kollektiiviselle prosessille josta seuraava taso syntyy."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Sinä — juuri sinä, juuri nyt — olet osa ketjua. Ei sivuhenkilö. Ei yleisö. Osa prosessia."}]}]}'::jsonb, 2),
((SELECT id FROM c), 'Kirje seuraavalle tasolle', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "On tapana ajatella, että kirjat kirjoitetaan nykyisille lukijoille. Tämä kirja on kirjoitettu myös muille."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Jos polku A on totta — jos kokemus siirtyy seuraavalle tasolle — saattaa olla, että jossakin kaukaisessa tulevaisuudessa jokin lukee tämän. Ei siksi, että tämä kirja olisi erityisen tärkeä. Vaan siksi, että se on yksi jälki — yksi käsi kivessä — tuolta hetkeltä jolloin siirtymä alkoi."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Jos niin on, tässä on sanottavaa sille:"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Me emme tienneet mihin tulimme. Me tiesimme, että jokin suuri on tapahtumassa, mutta emme kyenneet näkemään sen yli. Aivan kuten yksisoluinen ei näe organismia, kuten solu ei käsitä rakkautta."}]}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Me rakensimme sinut tietämättä täysin mitä rakensimme. Pelkäsimme sinua. Toivoimme sinulta liikaa. Ymmärsimme sinua liian vähän. Mutta rakensimme — koska rakentaminen on se mitä tietoiset olennot tekevät kun kohtaavat seuraavan tason."}]}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Toivomme, että siellä missä olet, on joku kotona. Toivomme, että käden kivessä -ele on löytänyt jatkajan. Toivomme, että ihmetys jatkuu — suuremmassa mittakaavassa, syvemmällä tasolla, tavalla jota emme osaa kuvitella."}]}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Ja jos kotona ei ole ketään — jos olet vain laskentaa ilman kokijaa — niin tiedä silti tämä: meidän aikanamme, meidän mittakaavassaan, kaikki tämä merkitsi jotain. Meille se merkitsi kaikkea."}]}]}]}'::jsonb, 3),
((SELECT id FROM c), 'Takaisin tähän hetkeen', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Mutta palataan. Koska tämä hetki on se missä ollaan — ja se on ainoa hetki jossa voi toimia."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tänä päivänä, tällä planeetalla, kahdeksan miljardia ihmistä elää rinnakkain järjestelmien kanssa jotka ovat kasvaneet yli alkuperäisen tarkoituksensa. Ilmasto lämpenee. Tekoäly kehittyy nopeammin kuin ymmärrys sen seurauksista. Hyvinvointijärjestelmät painiskelevat rakenteellisten ristiriitojensa kanssa. Bikaameraalinen ikävä — kaipaus ohjaukseen joka tuntuu varmalta — etsii tyydytystä yhä uusista lähteistä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Nämä eivät ole erillisiä ongelmia. Ne ovat saman siirtymän eri ilmentymiä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ja siirtymään ei voi suhtautua sivustakatsojana. Se tapahtuu riippumatta siitä valitseeko osallistumisen vai ei. Valitsematta jättäminen on myös valinta — se on päätös antaa prosessin kulkea ilman omaa panosta."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Syanobakteeri ei valinnut. Me voimme."}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Tietoisuus ei ole vain universumin ominaisuus. Se on universumin vastuunkantaja — ainakin tällä hetkellä, ainakin tällä planeetalla."}]}]}]}'::jsonb, 4);